sql_query:
SELECT "Trial name"
FROM clinical_trials
WHERE "Name of ICI" = 'Atezolizumab+Trastuzumab emtansine+Placebo' AND "Cancer type" = 'Mesothelioma';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Trial name" AS source_value FROM clinical_trials
WHERE "Name of ICI" = 'Atezolizumab+Trastuzumab emtansine+Placebo' AND "Cancer type" = 'Mesothelioma'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_trial_acronym(source_value) AS "trial_acronym"
FROM base;
